import static org.junit.jupiter.api.Assertions.*;
public class Jsoup_parse_1_Test {

    @Test
    @DisplayName("TC11: parse(File) reads HTML file and sets baseUri to file absolute path")
    public void test_TC11() throws Exception {
        // Arrange: create temp file with .html content to trigger DataUtil.load(file, null, absPath)
        Path tmp = Files.createTempFile("fnocharset", ".html");
        String html = "<h1>Hi</h1>";
        Files.write(tmp, html.getBytes(StandardCharsets.UTF_8));
        File file = tmp.toFile();

        // Act: parse without specifying charset or baseUri overload
        Document doc = Jsoup.parse(file);

        // Assert: HTML content found and baseUri equals the file's absolute path
        assertEquals("Hi", doc.select("h1").first().text(),
                "Expected the <h1> text to be parsed from file");
        assertEquals(file.getAbsolutePath(), doc.baseUri(),
                "Expected baseUri to be file.getAbsolutePath()");
    }

    @Test
    @DisplayName("TC12: parse(File,charset,baseUri,Parser) uses xmlParser to preserve case-sensitive tags")
    public void test_TC12() throws Exception {
        // Arrange: mixed-case tags in file to exercise xmlParser path vs HTML parser
        Path tmp = Files.createTempFile("fxml", ".html");
        String html = "<a>one</a><A>two</A>";
        Files.write(tmp, html.getBytes(StandardCharsets.UTF_8));
        File file = tmp.toFile();
        Parser xml = Parser.xmlParser();

        // Act: parse with UTF-8 charset, a baseUri, and xml parser
        Document doc = Jsoup.parse(file, "UTF-8", "http://x/", xml);

        // Assert: xmlParser should treat tags case-sensitively => only lowercase <a> retained by selector
        assertEquals(1, doc.select("a").size(),
                "xmlParser should only recognize lowercase <a>");
        assertTrue(doc.select("A").isEmpty(),
                "xmlParser should not match uppercase <A> tag");
    }

    @Test
    @DisplayName("TC13: parse(Path, charsetName, baseUri) reads from Path and resolves baseUri correctly")
    public void test_TC13() throws Exception {
        // Arrange: create a temp HTML file via Path to trigger DataUtil.load(path, charset, baseUri)
        Path tmp = Files.createTempFile("pcc", ".html");
        String html = "<p>PathOK</p>";
        Files.write(tmp, html.getBytes(StandardCharsets.UTF_8));

        // Act: parse using Path overload with UTF-8 and explicit baseUri
        Document doc = Jsoup.parse(tmp, "UTF-8", "http://p/uri");

        // Assert: element text matches and baseUri set to the passed argument
        assertEquals("PathOK", doc.select("p").first().text(),
                "Expected the <p> text to be parsed from Path");
        assertEquals("http://p/uri", doc.baseUri(),
                "Expected baseUri to equal the provided URI");
    }

    @Test
    @DisplayName("TC14: parse(InputStream, charsetName, baseUri) reads from stream and sets baseUri")
    public void test_TC14() throws Exception {
        // Arrange: byte stream for HTML to hit DataUtil.load(in, charset, baseUri)
        byte[] data = "<div>STM</div>".getBytes(StandardCharsets.UTF_8);
        InputStream in = new ByteArrayInputStream(data);

        // Act: parse from InputStream with charset and baseUri arguments
        Document doc = Jsoup.parse(in, "UTF-8", "http://s/uri");

        // Assert: parsed content and baseUri reflect input arguments
        assertEquals("STM", doc.select("div").first().text(),
                "Expected the <div> text to be parsed from InputStream");
        assertEquals("http://s/uri", doc.baseUri(),
                "Expected baseUri to equal the provided stream URI");
    }

    @Test
    @DisplayName("TC15: parse(String bodyHtml, String baseUri) fragment parser returns proper body content")
    public void test_TC15() {
        // Arrange: fragment HTML to exercise Parser.parseBodyFragment(path B0→Parser.parseBodyFragment)
        String frag = "<span>F</span>";

        // Act: parse body fragment with baseUri
        Document doc = Jsoup.parseBodyFragment(frag, "http://b/");

        // Assert: body HTML matches fragment and baseUri set correctly
        assertEquals("<span>F</span>", doc.body().html(),
                "Expected body HTML to match the fragment");
        assertEquals("http://b/", doc.baseUri(),
                "Expected baseUri to match provided baseUri");
    }

    @Test
    @DisplayName("TC16: parseBodyFragment(String) uses empty baseUri and returns fragment")
    public void test_TC16() {
        // Arrange: fragment HTML to exercise parseBodyFragment(html, \"\")
        String frag = "<i>item</i>";

        // Act: parse body fragment without specifying baseUri
        Document doc = Jsoup.parseBodyFragment(frag);

        // Assert: body HTML equals input fragment and baseUri is empty string
        assertEquals("<i>item</i>", doc.body().html(),
                "Expected body HTML to match the fragment input");
        assertEquals("", doc.baseUri(),
                "Expected baseUri to be empty when not provided");
    }

    @Test
    @DisplayName("TC17: parse(File) nonexistent file throws IOException")
    public void test_TC17() {
        // Arrange: a File object pointing to a non-existent path
        File missing = new File("no-such.html");

        // Act & Assert: expecting IOException when attempting to parse missing file
        assertThrows(IOException.class, () -> Jsoup.parse(missing),
                "Expected IOException for missing file overload");
    }
